cassandra().poll {
    connect {
        servers = listOf("localhost:9042")
        keySpace = "iot"
        datacenterName = "datacenter1"
    }
    query("SELECT deviceid, timestamp, batterylevel FROM devices WHERE company = ? ORDER BY timestamp")
    parameters("ACME Inc.")
    tieBreaker {
        name = "timestamp"
        type = GenericType.INSTANT
    }
    pollDelay(Duration.ofSeconds(1))
}

.cassandra()
.save {
    connect {
        servers = listOf("localhost:9042")
        keyspace = "iot"
        datacenterName = "datacenter1"
    }

    table { _, _ ->
        "batteryState"
    }

    columns { _, _ ->
        listOf(
            "company",
            "deviceid",
            "timestamp,
            "batterylevel"
        )
    }

    rows { _, input ->
        listOf(
            CassandraSaveRow(
                "'ACME Inc.'",
                "'${input.deviceId}'",
                "'${input.timestamp}'",
                input.batteryLevel
            )
        )
    }
}

 cassandra().search {
    name = "search"

    connect {
        servers = listOf("localhost:9042")
        keyspace = "test_keyspace"
        datacenterName = "test_datacenter"
    }
    query { _, _ ->
        "SELECT * FROM "batteryState" WHERE  "company"= ? AND "deviceid"" = ? AND timestamp = ?"
    }
    parameters { _, input ->
        listOf("ACME Inc.", input.input.deviceId, input.input.timestamp)
    }
}

